CREATE OR REPLACE FUNCTION public.admin_saved_views_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  new.updated_at := now();
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.archive_bug_reports(report_ids uuid[])
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT is_admin() THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  UPDATE bug_reports SET archived_at = now() WHERE id = ANY(report_ids);
END;
$function$

CREATE OR REPLACE FUNCTION public.bump_version_on_update()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  if NEW.version is null or NEW.version = OLD.version then
    NEW.version := OLD.version + 1;
  end if;
  return NEW;
end;
$function$

CREATE OR REPLACE FUNCTION public.fetch_sessions_windowed(p_cutoff timestamp with time zone)
 RETURNS SETOF sessions
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tz text; v_tz_valid boolean;
  v_now timestamptz := now();
begin
  select coalesce(timezone, 'America/Mexico_City') into v_tz
    from notification_preferences where user_id = (select auth.uid());
  if v_tz is null then v_tz := 'America/Mexico_City'; end if;
  select exists(select 1 from pg_timezone_names where name = v_tz) into v_tz_valid;
  if not v_tz_valid then v_tz := 'America/Mexico_City'; end if;

  return query
    select s.* from sessions s
    where s.user_id = (select auth.uid())
      and (
        s.created_at >= p_cutoff
        or (
          s.status = 'scheduled'
          and not public.session_counts_at(s.status, s.date, s.time, v_tz, v_now, s.created_at)
        )
      );
end;
$function$

CREATE OR REPLACE FUNCTION public.infer_short_date_year(m smallint, d smallint, ref timestamp with time zone, p_tz text)
 RETURNS smallint
 LANGUAGE plpgsql
 IMMUTABLE PARALLEL SAFE
AS $function$
declare
  ref_date date := (ref at time zone p_tz)::date;
  ref_year smallint := extract(year from ref_date)::smallint;
  best_year smallint := ref_year;
  best_diff integer := 1000000;
  y smallint;
  cand date;
  diff integer;
begin
  for y in select unnest(array[ref_year - 1, ref_year, ref_year + 1]) loop
    begin
      cand := make_date(y::int, m::int, d::int);
      diff := abs(cand - ref_date);
      if diff < best_diff then
        best_diff := diff;
        best_year := y;
      end if;
    exception when others then
      null;
    end;
  end loop;
  return best_year;
end;
$function$

CREATE OR REPLACE FUNCTION public.normalize_short_date(raw text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  parts TEXT[];
  d INT;
  m TEXT;
BEGIN
  IF raw IS NULL THEN RETURN NULL; END IF;
  parts := regexp_split_to_array(btrim(raw), '[\s-]+');
  IF array_length(parts, 1) < 2 THEN RETURN raw; END IF;
  BEGIN
    d := parts[1]::INT;
  EXCEPTION WHEN OTHERS THEN
    RETURN raw;
  END;
  m := parts[2];
  IF m NOT IN ('Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic') THEN
    RETURN raw;
  END IF;
  RETURN d::TEXT || '-' || m;
END;
$function$

CREATE OR REPLACE FUNCTION public.payments_normalize_date()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.date := normalize_short_date(NEW.date);
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.recalc_patient_session_counters(p_patient_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_patient_rate integer; v_user_id uuid; v_tz text; v_tz_valid boolean;
  v_sessions integer; v_billed integer;
  v_now timestamptz := now();
begin
  select rate, user_id into v_patient_rate, v_user_id from patients where id = p_patient_id;
  if v_user_id is null then return; end if;
  select coalesce(timezone, 'America/Mexico_City') into v_tz
    from notification_preferences where user_id = v_user_id;
  if v_tz is null then v_tz := 'America/Mexico_City'; end if;
  select exists(select 1 from pg_timezone_names where name = v_tz) into v_tz_valid;
  if not v_tz_valid then v_tz := 'America/Mexico_City'; end if;
  select count(*)::integer into v_sessions from sessions where patient_id = p_patient_id;
  select coalesce(sum(coalesce(s.rate, v_patient_rate, 0)), 0)::integer into v_billed
    from sessions s
    where s.patient_id = p_patient_id
      and public.session_counts_at(s.status, s.date, s.time, v_tz, v_now, s.created_at);
  update patients set sessions = coalesce(v_sessions, 0), billed = coalesce(v_billed, 0)
    where id = p_patient_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.session_counts_at(p_status text, p_date text, p_time text, p_tz text, ref timestamp with time zone, p_created_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS boolean
 LANGUAGE plpgsql
 IMMUTABLE PARALLEL SAFE
AS $function$
declare
  parts text[];
  d_num smallint; mon text; m smallint;
  yr_suffix text; y smallint;
  hh smallint := 0; mm smallint := 0;
  tp text[];
  session_end_local timestamp;
  session_end_at timestamptz;
  anchor timestamptz := coalesce(p_created_at, ref);
begin
  if p_status = 'completed' or p_status = 'charged' then return true; end if;
  if p_status <> 'scheduled' then return false; end if;
  parts := regexp_match(p_date, '^([0-9]+)-(Ene|Feb|Mar|Abr|May|Jun|Jul|Ago|Sep|Oct|Nov|Dic)(?:-([0-9]{2}))?$');
  if parts is null then return false; end if;
  d_num := parts[1]::smallint;
  mon := parts[2];
  m := public.spanish_month_idx(mon);
  if m is null then return false; end if;
  yr_suffix := parts[3];
  if yr_suffix is not null then
    y := (2000 + yr_suffix::smallint)::smallint;
  else
    -- Anchor on created_at (falls back to ref/now when null), not ref.
    y := public.infer_short_date_year(m, d_num, anchor, p_tz);
  end if;
  tp := string_to_array(p_time, ':');
  if array_length(tp, 1) >= 2 then
    hh := tp[1]::smallint; mm := tp[2]::smallint;
  end if;
  begin
    session_end_local := make_timestamp(y::int, m::int, d_num::int, hh::int, mm::int, 0) + interval '1 hour';
  exception when others then return false;
  end;
  session_end_at := session_end_local at time zone p_tz;
  -- "has the slot passed" still compares against now (ref), not the anchor.
  return ref >= session_end_at;
end;
$function$

