$function$

CREATE OR REPLACE FUNCTION public.snapshot_note(p_note_id uuid, p_title_ciphertext text, p_content_ciphertext text, p_encrypted boolean, p_debounce_seconds integer DEFAULT 60, p_cap integer DEFAULT 50)
 RETURNS integer
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_user_id uuid;
  v_latest_at timestamptz;
  v_latest_no integer;
  v_next_no integer;
begin
  v_user_id := auth.uid();
  if v_user_id is null then
    raise exception 'unauthenticated' using errcode = '42501';
  end if;
  if not exists (select 1 from notes where id = p_note_id and user_id = v_user_id) then
    raise exception 'note not found' using errcode = 'P0002';
  end if;
  select created_at, version_no into v_latest_at, v_latest_no
  from note_versions
  where note_id = p_note_id
  order by version_no desc
  limit 1;
  if v_latest_at is not null and now() - v_latest_at < make_interval(secs => p_debounce_seconds) then
    update note_versions
    set title_ciphertext = p_title_ciphertext,
        content_ciphertext = p_content_ciphertext,
        encrypted = p_encrypted,
        created_at = now()
    where note_id = p_note_id and version_no = v_latest_no;
    return v_latest_no;
  end if;
  v_next_no := coalesce(v_latest_no, 0) + 1;
  insert into note_versions (note_id, user_id, version_no, title_ciphertext, content_ciphertext, encrypted)
    values (p_note_id, v_user_id, v_next_no, p_title_ciphertext, p_content_ciphertext, p_encrypted);
  delete from note_versions
  where note_id = p_note_id
    and version_no <= v_next_no - greatest(1, coalesce(p_cap, 50));
  return v_next_no;
end;
$function$

CREATE OR REPLACE FUNCTION public.trg_payments_recalc_paid()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if (tg_op = 'INSERT') then
    if new.patient_id is not null then
      perform public.recalc_patient_paid(new.patient_id);
    end if;
  elsif (tg_op = 'UPDATE') then
    if old.patient_id is distinct from new.patient_id then
      if old.patient_id is not null then perform public.recalc_patient_paid(old.patient_id); end if;
      if new.patient_id is not null then perform public.recalc_patient_paid(new.patient_id); end if;
    elsif old.amount is distinct from new.amount then
      if new.patient_id is not null then perform public.recalc_patient_paid(new.patient_id); end if;
    end if;
  elsif (tg_op = 'DELETE') then
    if old.patient_id is not null then perform public.recalc_patient_paid(old.patient_id); end if;
  end if;
  return null;
end;
$function$

CREATE OR REPLACE FUNCTION public.trg_sessions_recalc_counters()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if (tg_op = 'INSERT') then
    if new.patient_id is not null then
      perform public.recalc_patient_session_counters(new.patient_id);
    end if;
  elsif (tg_op = 'UPDATE') then
    if old.patient_id is distinct from new.patient_id then
      if old.patient_id is not null then perform public.recalc_patient_session_counters(old.patient_id); end if;
      if new.patient_id is not null then perform public.recalc_patient_session_counters(new.patient_id); end if;
    elsif old.status is distinct from new.status
       or old.date is distinct from new.date
       or old.time is distinct from new.time
       or old.rate is distinct from new.rate then
      if new.patient_id is not null then perform public.recalc_patient_session_counters(new.patient_id); end if;
    end if;
  elsif (tg_op = 'DELETE') then
    if old.patient_id is not null then perform public.recalc_patient_session_counters(old.patient_id); end if;
  end if;
  return null;
end;
$function$

CREATE OR REPLACE FUNCTION public.update_session_status_atomic(p_session_id uuid, p_new_status text, p_cancel_reason text, p_expected_version integer DEFAULT NULL::integer)
 RETURNS json
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_user_id uuid;
  v_session sessions%rowtype;
  v_exists boolean;
begin
  v_user_id := auth.uid();
  if v_user_id is null then
    raise exception 'unauthenticated' using errcode = '42501';
  end if;

  if p_new_status not in ('scheduled', 'completed', 'cancelled', 'charged') then
    raise exception 'invalid status: %', p_new_status using errcode = '22023';
  end if;

  update sessions
  set status = p_new_status,
      cancel_reason = case
        when p_new_status in ('scheduled', 'completed') then null
        else p_cancel_reason
      end
  where id = p_session_id
    and user_id = v_user_id
    and (p_expected_version is null or version = p_expected_version)
  returning * into v_session;

  if not found then
    select exists(select 1 from sessions where id = p_session_id and user_id = v_user_id)
      into v_exists;
    if v_exists and p_expected_version is not null then
      raise exception 'session version conflict' using errcode = '40001';
    end if;
    raise exception 'session not found' using errcode = 'P0002';
  end if;

  return json_build_object('session', row_to_json(v_session));
end;
$function$
